<div class="page-head"><div><h2>Reimbursement</h2><p class="muted">Claim request, finance approval, reporting, and Accurate-ready payable data.</p></div></div>
<div class="grid grid-2"><div class="card"><h3>Create Claim</h3><form method="post" action="<?=url('/reimbursement/store')?>"><?=csrf_field()?><div class="form-row"><div><label>Employee</label><select name="employee_id"><?php foreach($employees as $e): ?><option value="<?=e($e['id'])?>"><?=e($e['full_name'])?></option><?php endforeach; ?></select></div><div><label>Claim Type</label><input name="claim_type" placeholder="Medical, Transport, Operational" required></div><div><label>Amount</label><input name="amount" type="number" step="0.01"></div><div><label>Description</label><input name="description"></div></div><br><button class="btn btn-primary">Submit Claim</button></form></div><div class="card"><h3>Report</h3><div class="grid grid-3"><div><div class="muted">Total Claims</div><div class="stat"><?=count($rows)?></div></div><div><div class="muted">Pending</div><div class="stat"><?=count(array_filter($rows,fn($r)=>$r['status']==='pending'))?></div></div><div><div class="muted">Approved Amount</div><div class="stat"><?=money_id(array_sum(array_map(fn($r)=>$r['status']==='approved'?(float)$r['amount']:0,$rows)))?></div></div></div></div></div><br>
<div class="card"><h3>List Data & Approval</h3><table class="table"><tr><th>Employee</th><th>Type</th><th>Amount</th><th>Description</th><th>Status</th><th>Action</th></tr><?php foreach($rows as $r): ?><tr><td><?=e($r['employee_name'])?></td><td><?=e($r['claim_type'])?></td><td><?=money_id($r['amount'])?></td><td><?=e($r['description'])?></td><td><span class="badge badge-warning"><?=e($r['status'])?></span></td><td><form method="post" action="<?=url('/reimbursement/workflow')?>" style="display:flex;gap:6px"><?=csrf_field()?><input type="hidden" name="id" value="<?=e($r['id'])?>"><select name="status"><option>approved</option><option>rejected</option><option>paid</option></select><button class="btn btn-light">Update</button></form></td></tr><?php endforeach; ?></table></div>
